mapper.select:
select template_id, template_name, report_type, sections, data_scope, style_config, version_no, status, create_by, create_time, update_by, update_time, remark from nc_report_template
del_flag = '0'
AND template_name like '%' || #{templateName} || '%'
AND report_type = #{reportType}
AND status = #{status}
order by create_time desc, template_id desc

mapper.update:
update nc_report_template
template_name = #{templateName}, report_type = #{reportType}, sections = #{sections}, data_scope = #{dataScope}, style_config = #{styleConfig}, version_no = #{versionNo}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where template_id = #{templateId}

update nc_report_template set del_flag = '2'
where template_id in

    #{templateId}

mapper.select:
select t.task_id, t.task_name, t.template_id, coalesce(p.template_name, t.template_name) as template_name, t.report_period, t.report_scope, t.generate_mode, t.task_status, t.generated_file_name, t.generated_word_file_name, t.generated_excel_file_name, t.template_version, t.generated_by, t.snapshot_content, t.generated_time, t.create_by, t.create_time, t.update_by, t.update_time, t.remark from nc_report_generation_task t left join nc_report_template p on p.template_id = t.template_id
t.del_flag = '0'
AND t.task_name like '%' || #{taskName} || '%'
AND t.task_status = #{taskStatus}
AND t.report_period = #{reportPeriod}
order by t.create_time desc, t.task_id desc

mapper.update:
update nc_report_generation_task
task_name = #{taskName}, template_id = #{templateId}, template_name = #{templateName}, report_period = #{reportPeriod}, report_scope = #{reportScope}, generate_mode = #{generateMode}, task_status = #{taskStatus}, generated_file_name = #{generatedFileName}, generated_word_file_name = #{generatedWordFileName}, generated_excel_file_name = #{generatedExcelFileName}, template_version = #{templateVersion}, generated_by = #{generatedBy}, snapshot_content = #{snapshotContent}, generated_time = #{generatedTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where task_id = #{taskId}

mapper.select:
select count(distinct b.batch_id)
from nc_fusion_collection_batch b

    inner join nc_fusion_collection_item i on i.batch_id = b.batch_id and i.del_flag = '0'

where b.del_flag = '0'

    and b.period_key = #{reportPeriod}


    and coalesce(b.region_name, '') = #{scopeRegionName}


    and i.indicator_id = #{scopeIndicatorId}

select count(1)
from nc_fusion_collection_item i
inner join nc_fusion_collection_batch b on b.batch_id = i.batch_id
where i.del_flag = '0'
  and b.del_flag = '0'

    and b.period_key = #{reportPeriod}


    and coalesce(b.region_name, '') = #{scopeRegionName}


    and i.indicator_id = #{scopeIndicatorId}

select count(1)
from nc_warning_message w
where w.del_flag = '0'

    and w.period_key = #{reportPeriod}


    and coalesce(w.region_name, '') = #{scopeRegionName}


    and w.indicator_id = #{scopeIndicatorId}

select count(1)
from nc_rectification_issue i
left join nc_warning_message w on w.message_id = i.source_warning_id and w.del_flag = '0'
where i.del_flag = '0'

    and (
        (i.source_warning_id is not null and w.period_key = #{reportPeriod})
        or
        (i.source_warning_id is null


                    and to_char(i.create_time, 'YYYY') = #{reportPeriod}


                    and (to_char(i.create_time, 'YYYY') || 'Q' || to_char(i.create_time, 'Q')) = #{reportPeriod}


                    and to_char(i.create_time, 'YYYY-MM') = #{reportPeriod}


        )
    )


    and coalesce(nullif(i.region_name, ''), w.region_name, '') = #{scopeRegionName}


    and coalesce(i.indicator_id, w.indicator_id) = #{scopeIndicatorId}

select count(1)
from survey_task_sample s
inner join survey_task t on t.task_id = s.task_id
where t.del_flag = '0'



            and to_char(coalesce(t.dispatch_time, t.create_time), 'YYYY') = #{reportPeriod}


            and (to_char(coalesce(t.dispatch_time, t.create_time), 'YYYY') || 'Q' || to_char(coalesce(t.dispatch_time, t.create_time), 'Q')) = #{reportPeriod}


            and to_char(coalesce(t.dispatch_time, t.create_time), 'YYYY-MM') = #{reportPeriod}




    and coalesce(s.region_name, '') = #{scopeRegionName}


    and 1 = 0

select count(1)
from survey_response r
left join survey_task_sample s on s.sample_id = r.sample_id
where r.status = '0'



            and to_char(r.submit_time, 'YYYY') = #{reportPeriod}


            and (to_char(r.submit_time, 'YYYY') || 'Q' || to_char(r.submit_time, 'Q')) = #{reportPeriod}


            and to_char(r.submit_time, 'YYYY-MM') = #{reportPeriod}




    and coalesce(s.region_name, '') = #{scopeRegionName}


    and 1 = 0
